Reverse a Doubly Linked Listclass Node: # Constructor to create a new node def __init__(self, data): self.data = data self.next = None self.prev = None class DoublyLinkedList: # Constructor for empty Doubly Linked List def __init__(self): self.head = None # Function reverse a Doubly Linked List def reverse(self): temp = None current = self.head # Swap next and prev for all nodes of # doubly linked list while current is not None: temp = current.prev current.prev = current.next current.next = temp current = current.prev # Before changing head, check for the cases like # empty list and list with only one node if temp is not None: self.head = temp.prev # Given a reference to the head of a list and an # integer,inserts a new node on the front of list def push(self, new_data): # 1. Allocates node # 2. Put the data in it new_node = Node(new_data) # 3. Make next of new node as head and # previous as None (already None) new_node.next = self.head # 4. change prev of head node to new_node if self.head is not None: self.head.prev = new_node # 5. move the head to point to the new node self.head = new_node def printList(self, node): while(node is not None): print node.data, node = node.next # Driver program to test the above functions dll = DoublyLinkedList() dll.push(2); dll.push(4); dll.push(8); dll.push(10); print &quot;
Original Linked List&quot;dll.printList(dll.head) # Reverse doubly linked list dll.reverse() print &quot;
 Reversed Linked List&quot;dll.printList(dll.head) Reverse a linked listclass Node: # Constructor to initialize the node object def __init__(self, data): self.data = data self.next = None class LinkedList: # Function to initialize head def __init__(self): self.head = None # Function to reverse the linked list def reverse(self): prev = None current = self.head while(current is not None): next = current.next current.next = prev prev = current current = next self.head = prev # Function to insert a new node at the beginning def push(self, new_data): new_node = Node(new_data) new_node.next = self.head self.head = new_node # Utility function to print the linked LinkedList def printList(self): temp = self.head while(temp): print temp.data, temp = temp.next # Driver program to test above functions llist = LinkedList() llist.push(20) llist.push(4) llist.push(15) llist.push(85) print &quot;Given Linked List&quot;llist.printList() llist.reverse() print &quot;
Reversed Linked List&quot;llist.printList() Insert value in sorted way in a sorted doubly linked listsortedInsert(head_ref, newNode) if (head_ref == NULL) head_ref = newNode else if head_ref-&gt;data &gt;= newNode-&gt;data newNode-&gt;next = head_ref newNode-&gt;next-&gt;prev = newNode head_ref = newNode else Initialize current = head_ref while (current-&gt;next != NULL and current-&gt;next-&gt;data data) current = current-&gt;next # insert first newNode-&gt;next = current-&gt;next if current-&gt;next != NULL newNode-&gt;next-&gt;prev = newNode # deal with current node current-&gt;next = newNode newNode-&gt;prev = current Construct Tree from given Inorder and Preorder traversalsAlgorithm: buildTree()1) Pick an element from Preorder. Increment a Preorder Index Variable (preIndex in below code) to pick next element in next recursive call.2) Create a new tree node tNode with the data as picked element.3) Find the picked element’s index in Inorder. Let the index be inIndex.4) Call buildTree for elements before inIndex and make the built tree as left subtree of tNode.5) Call buildTree for elements after inIndex and make the built tree as right subtree of tNode.6) return tNode. # A binary tree node class Node: # Constructor to create a new node def __init__(self, data): self.data = data self.left = None self.right = None &quot;&quot;&quot;Recursive function to construct binary of size len from Inorder traversal in[] and Preorder traversal pre[]. Initial values of inStrt and inEnd should be 0 and len -1. The function doesn&apos;t do any error checking for cases where inorder and preorder do not form a tree &quot;&quot;&quot;def buildTree(inOrder, preOrder, inStrt, inEnd): if (inStrt &gt; inEnd): return None # Pich current node from Preorder traversal using # preIndex and increment preIndex tNode = Node(preOrder[buildTree.preIndex]) buildTree.preIndex += 1 # If this node has no children then return if inStrt == inEnd : return tNode # Else find the index of this node in Inorder traversal inIndex = search(inOrder, inStrt, inEnd, tNode.data) # Using index in Inorder Traversal, construct left # and right subtrees tNode.left = buildTree(inOrder, preOrder, inStrt, inIndex-1) tNode.right = buildTree(inOrder, preOrder, inIndex+1, inEnd) return tNode # UTILITY FUNCTIONS # Function to find index of vaue in arr[start...end] # The function assumes that value is rpesent in inOrder[] def search(arr, start, end, value): for i in range(start, end+1): if arr[i] == value: return i def printInorder(node): if node is None: return # first recur on left child printInorder(node.left) #then print the data of node print node.data, # now recur on right child printInorder(node.right) # Driver program to test above function inOrder = [&apos;D&apos;, &apos;B&apos; ,&apos;E&apos;, &apos;A&apos;, &apos;F&apos;, &apos;C&apos;] preOrder = [&apos;A&apos;, &apos;B&apos;, &apos;D&apos;, &apos;E&apos;, &apos;C&apos;, &apos;F&apos;] # Static variable preIndex buildTree.preIndex = 0root = buildTree(inOrder, preOrder, 0, len(inOrder)-1) # Let us test the build tree by priting Inorder traversal print &quot;Inorder traversal of the constructed tree is&quot;printInorder(root) the difference between an exclusive lock and a shared lockI wrote this answer down because I thought this would be a fun (and fitting) analogy: Think of a lockable object as a blackboard (lockable) in a class room containing a teacher (writer) and many students (readers). While a teacher is writing something (exclusive lock) on the board: Nobody can read it, because it’s still being written, and she’s blocking your view =&gt; If an object is exclusively locked, shared locks cannot be obtained. Other teachers won’t come up and start writing either, or the board becomes unreadable, and confuses students =&gt; If an object is exclusively locked, other exclusive locks cannot be obtained. When the students are reading (shared locks) what is on the board: They all can read what is on it, together =&gt; Multiple shared locks can co-exist. The teacher waits for them to finish reading before she clears the board to write more =&gt; If one or more shared locks already exist, exclusive locks cannot be obtained. Exclusive lock (X) – This lock type, when imposed, will ensure that a page or row will be reserved exclusively for the transaction that imposed the exclusive lock, as long as the transaction holds the lock.The exclusive lock will be imposed by the transaction when it wants to modify the page or row data, which is in the case of DML statements DELETE, INSERT and UPDATE. An exclusive lock can be imposed to a page or row only if there is no other shared or exclusive lock imposed already on the target. This practically means that only one exclusive lock can be imposed to a page or row, and once imposed no other lock can be imposed on locked resources Shared lock (S) – this lock type, when imposed, will reserve a page or row to be available only for reading, which means that any other transaction will be prevented to modify the locked record as long as the lock is active. However, a shared lock can be imposed by several transactions at the same time over the same page or row and in that way several transactions can share the ability for data reading since the reading process itself will not affect anyhow the actual page or row data. In addition, a shared lock will allow write operations, but no DDL changes will be allowed Describe the ways to defend DDos Set Traffic ThresholdsYou probably track how many users visit your site per day, per hour, and per minute. Thus, you understand your average traffic levels and, hopefully, you’ve recorded how special events (sales, big news releases, etc.) affect visits. Based on these numbers, set thresholds that automatically flag abnormal traffic for your security team. If you expect 1,000 visitors per 10 minutes, an influx of 5,000 visitors over one minute should trigger your alert. Blacklist and WhitelistControl who can access your network and APIs with whitelists and blacklists. However, do not automatically blacklist IP addresses that trigger alerts. You will see false positives, and overreacting is a sure way to infuriate good customers. Temporarily block traffic and see how it responds. Legitimate users usually try again after a few minutes. Illegitimate traffic tends to switch IP addresses. CDNsThe best defense against DDoS attacks is a content delivery network (CDN) like Prolexic (acquired by Akamai), Incapsula, Arbor Networks, or CloudFlare. They can identify illegitimate traffic and divert it to their cloud infrastructure. The problem is that CDNs are not cheap. A typical plan costs five figures per month. Or, if you pay per incident, you might get a six-figure bill for one attack. If you run a bank, a massive ecommerce company, or a social platform that makes thousands of dollars per second, that’s a small price to pay. Most companies either can’t afford a CDN or don’t have a platform that warrants such high security. If, for instance, your company has an informational website where no one makes transactions or uses services, you don’t need a CDN. You’re not a prime target. An application or network firewall might be enough to prevent abnormal traffic. If a DDoS attack takes you down, it won’t harm customers or your reputation. The cheapest way to defend against DDoS attacks is to deploy more servers when you detect suspicious activity. That is the least reliable method but still better than nothing. Remember, there is no end to the amount of money you can throw at security. Depending on your budget and risk tolerance, choose the right option for your service desk. Automate Communication with CustomersWhen a DDoS attack succeeds, you don’t want your service desk buried in emails, phone calls, social media posts, and instant messages. Create a status page that automatically displays whether your service is up or down. Also, create DDoS communications templates that you can auto-send to end users who contact you. These templates should cover any interruption to service, not just DDoS attacks. Keep it vague with something like: “Thank you for contacting [your company name]. Our platform is currently down. We are working as quickly as possible to restore service. We will post updates on our status page [hyperlinked] as soon as we have more information”. Incident Report and Root Cause AnalysisAfter you suffer an attack, you need to reestablish credibility. Draft an incident report explaining what happened, why, and how you responded. Then, discuss how you will prevent future attacks. If you contracted a CDN, for instance, discuss how it works and how it will deter future attacks. Open the report with simple, non-technical language. You can add a technical section for CIOs, CTOs, and others who would appreciate the details. Practice for AttacksSimulate DDoS attacks to gauge how your action plan works. You could give DevOps and the service desk warning or take them by surprise to make the simulation realistic. Companies often run simulations in a planned maintenance window to spare end users further inconvenience. If you have a CDN, you can warn the provider, or not. Obviously if you pay per incident, coordinate tests with the CDN provider. Internet Service Provider (ISP). Some enterprises use their ISP to provide DDoS mitigation. These ISP’s have more bandwidth than an enterprise would, which can help with the large volumetric attacks, but there are three key problems with these services as well 网络层DDos攻击网络层DDos攻击包括SYN flood、UDP flood、ICMP flood等。 SYN flood攻击 SYN flood攻击主要利用了TCP三次握手过程中的bug，我们知道TCP三次握手过程是要建立连接的双方发送SYN，SYN+ACK，ACK数据包，而当攻击方随意构造源ip去发送SYN包时，服务器返回的SYN+ACK就不能得到应答（因为ip是随意构造的），此时服务器就会尝试重新发送，并且会有至少30s的等待时间，导致资源饱和服务不可用，此攻击属于慢型dos攻击。 UDP flood攻击 由于udp是一种无连接的协议，因此攻击者可以伪造大量的源IP地址去发送udp包，此种攻击属于大流量攻击。正常应用情况下，UDP包双向流量会基本相等，因此在消耗对方资源的时候也在消耗自己的资源。 ICMP flood攻击 此攻击属于大流量攻击，其原理就是不断发送不正常的ICMP包（所谓不正常就是ICMP包内容很大），导致目标带宽被占用，但其本身资源也会被消耗。并且目前很多服务器都是禁ping的（在防火墙在可以屏蔽icmp包），因此这种方式已经落伍。 网络层DDos防御 网络架构上做好优化，采用负载均衡分流。 添加抗DDos设备，流量清洗。 限制单ip请求频率。 防火墙等防护设置禁止icmp包等 网络层的DDos攻击究其本质其实是无法防御的，我们能做得就是不断优化自身的网络架构，以及提升网络带宽。 应用层DDos攻击 判断User-Agent字段（不可靠，因为可以随意构造） 网页中镶嵌js代码（不可靠，因为爬虫也可携带浏览器引擎，或者执行js代码） 针对ip+cookie，限制访问频率（由于cookie可以更改，ip可以使用代理，或者肉鸡，也不可靠) 关闭apache最大连接数等，合理配置中间件，缓解ddos攻击。 页面中添加验证码，比如搜索数据库时。 编写代码时，尽量实现优化，并合理使用缓存技术，减少数据库的读取操作。 CSRFSynchronizer token pattern(STP)对于每个request，在服务器端生成一个新的csrf_token，并将其返回在页面的表单中。在服务器端每次接收到请求时，都会验证表单中是否包含正确的csrf_token。由于第三方网站无法得知正确的csrf_token，所以无法进行csrf攻击。 get_token = get_random_token() return &#123; &lt;form&gt; &lt;input name=field1&gt;&lt;/input&gt; &lt;input type=&quot;hidden&quot; name=&quot;csrfmiddlewaretoken&quot; value=#&#123;get_token()&#125; /&gt; &lt;/form&gt;&#125; 这个方法的好处是客户端不需要支持javascript，因此通用于所有的网站。坏处是由于服务器端对于每个请求都会更换csrf_token，因此他需要保证用户提交的表单是用户最近一次请求的表单。如果用户通过多个tab同时浏览该网站，那么往往会导致用户提交的表单不是最新的那一个。 Cookie-to-header token第二个方法是为每个session生成一个csrf_token，随后将csrf_token保存到cookie中，之后通过javascript在每次请求时将csrf_token设置到http header中的X-Csrf-Token属性中。再在服务器端比较Cookie的csrf_token与header中的token是否一致。 //当用户登录时设置CookieSet-Cookie: Csrf-token=i8XNjC4b8KVok4uw5RftR38Wgp2BFwql; expires=Thu, 23-Jul-2015 10:25:33 GMT; Max-Age=31449600; Path=/ //当用户发送请求时设置Http Header中的X-Csrf-TokenX-Csrf-Token: i8XNjC4b8KVok4uw5RftR38Wgp2BFwql有些读者可能会问如果设置在Cookie中，那么Malicious.com岂不是可以利用Cookie中的值来设置X-Csrf-Token的值么？ 其实尽管可以从Malicious.com发送给Trusted.com带有含有csrf_token的Cookie，但是根据同源策略，Javascript无法从Malicious.com读取或者写入Trusted.com的Cookie。所以Malicious.com无法知道正确的csrf_token是什么，也不能够正确的修改Http-Header的X-Csrf-Token属性。 explain routing mechanism in SPAhash 的历史最开始的网页是多页面的，后来出现了 Ajax 之后，才慢慢有了 SPA。然而，那时候的 SPA 有两个弊端： 用户在使用的过程中，url 不会发生任何改变。当用户操作了几步之后，一不小心刷新了页面，又会回到最开始的状态。由于缺乏 url，不方便搜索引擎进行收录。怎么办呢？ → 使用 hashurl 上的 hash 本意是用来作锚点的，方便用户在一个很长的文档里进行上下的导航，用来做 SPA 的路由控制并非它的本意。然而，hash 满足这么一种特性：改变 url 的同时，不刷新页面，再加上浏览器也提供 onhashchange 这样的事件监听，因此，hash 能用来做路由控制。（这部分红宝书 P394 也有相关的说明）后来，这种模式大行其道，onhashchange 也就被写进了 HTML5 规范当中去了。 history 的演进很早以前，浏览器便实现了 history。然而，早期的 history 只能用于多页面进行跳转，比如： // 这部分可参考红宝书 P215history.go(-1); // 后退一页history.go(2); // 前进两页history.forward(); // 前进一页history.back(); // 后退一页在 HTML5 规范中，history 新增了以下几个 API history.pushState(); // 添加新的状态到历史状态栈history.replaceState(); // 用新的状态代替当前状态history.state // 返回当前状态对象通过history.pushState或者history.replaceState，也能做到：改变 url 的同时，不会刷新页面。所以 history 也具备实现路由控制的潜力。然而，还缺一点：hash 的改变会触发 onhashchange 事件，history 的改变会触发什么事件呢？ → 很遗憾，没有。怎么办呢？→ 虽然我们无法监听到 history 的改变事件，然而，如果我们能罗列出所有可能改变 history 的途径，然后在这些途径一一进行拦截，不也一样相当于监听了 history 的改变吗？对于一个应用而言，url 的改变只能由以下 3 种途径引起： 点击浏览器的前进或者后退按钮；点击 a 标签；在 JS 代码中直接修改路由第 2 和第 3 种途径可以看成是一种，因为 a 标签的默认事件可以被禁止，进而调用 JS 方法。关键是第 1 种，HTML5 规范中新增了一个 onpopstate 事件，通过它便可以监听到前进或者后退按钮的点击。要特别注意的是：调用history.pushState和history.replaceState并不会触发 onpopstate 事件。 what is the difference: cookie and sessionA cookie is a bit of data stored by the browser and sent to the server with every request. A session is a collection of data stored on the server and associated with a given user (usually via a cookie containing an id code) 层次遍历"""Definition of TreeNode:class TreeNode: def __init__(self, val): self.val = val self.left, self.right = None, None"""class Solution: """ @param root: The root of binary tree. @return: Level order in a list of lists of integers """ def levelOrder(self, root): # write your code here res = [] # 如果根节点为空，则返回空列表 if root is None: return res # 模拟一个队列储存节点 q = [] # 首先将根节点入队 q.append(root) # 列表为空时，循环终止 while len(q) != 0: # 使用列表存储同层节点 tmp = [] # 记录同层节点的个数 length = len(q) for i in range(length): # 将同层节点依次出队 r = q.pop(0) if r.left is not None: # 非空左孩子入队 q.append(r.left) if r.right is not None: # 非空右孩子入队 q.append(r.right) tmp.append(r.val) res.append(tmp) return res Level Order Tree Traversal# A node structure class Node: # A utility function to create a new node def __init__(self, key): self.data = key self.left = None self.right = None # Function to print level order traversal of tree def printLevelOrder(root): h = height(root) for i in range(1, h+1): printGivenLevel(root, i) # Print nodes at a given level def printGivenLevel(root , level): if root is None: return if level == 1: print &quot;%d&quot; %(root.data), elif level &gt; 1 : printGivenLevel(root.left , level-1) printGivenLevel(root.right , level-1) &quot;&quot;&quot; Compute the height of a tree--the number of nodes along the longest path from the root node down to the farthest leaf node &quot;&quot;&quot;def height(node): if node is None: return 0 else : # Compute the height of each subtree lheight = height(node.left) rheight = height(node.right) #Use the larger one if lheight &gt; rheight : return lheight+1 else: return rheight+1 # Driver program to test above function root = Node(1) root.left = Node(2) root.right = Node(3) root.left.left = Node(4) root.left.right = Node(5) print &quot;Level order traversal of binary tree is -&quot;printLevelOrder(root) # A node structure class Node: # A utility function to create a new node def __init__(self ,key): self.data = key self.left = None self.right = None # Iterative Method to print the height of binary tree def printLevelOrder(root): # Base Case if root is None: return # Create an empty queue for level order traversal queue = [] # Enqueue Root and initialize height queue.append(root) while(len(queue) &gt; 0): # Print front of queue and remove it from queue print queue[0].data, node = queue.pop(0) #Enqueue left child if node.left is not None: queue.append(node.left) # Enqueue right child if node.right is not None: queue.append(node.right) #Driver Program to test above function root = Node(1) root.left = Node(2) root.right = Node(3) root.left.left = Node(4) root.left.right = Node(5) print &quot;Level Order Traversal of binary tree is -&quot;printLevelOrder(root)
